mapper.insert:
merge into SourceInfo a using (select #{sourceInfo.sourceProtocol,jdbcType=VARCHAR} as sourceProtocol, #{sourceInfo.tableName,jdbcType=VARCHAR} as tableName, #{sourceInfo.sourceSystem,jdbcType=VARCHAR} as sourceSystem from dual) b on ( upper(a.SOURCEPROTOCOL) = upper(b.sourceProtocol) and upper(a.TABLENAME) = upper(b.tableName) and upper(a.SOURCESYSTEM) = upper(b.sourceSystem)) when matched then update set id = #{sourceInfo.id}
,UPDATE_TIME = #{sourceInfo.updateTime}
,SOURCEFIRM = #{sourceInfo.sourceFirm,jdbcType=VARCHAR}
when not matched then insert values (#{sourceInfo.id},#{sourceInfo.createTime},#{sourceInfo.updateTime}, #{sourceInfo.sourceProtocol,jdbcType=VARCHAR},#{sourceInfo.tableName,jdbcType=VARCHAR}, #{sourceInfo.sourceSystem,jdbcType=VARCHAR},#{sourceInfo.sourceFirm,jdbcType=VARCHAR},null,null,null,null,null)

merge into SourceInfo a using (select #{sourceInfo.sourceProtocol,jdbcType=VARCHAR} as sourceProtocol, #{sourceInfo.tableName,jdbcType=VARCHAR} as tableName, #{sourceInfo.sourceSystem,jdbcType=VARCHAR} as sourceSystem from dual) b on ( upper(a.SOURCEPROTOCOL) = upper(b.sourceProtocol) and upper(a.TABLENAME) = upper(b.tableName) and upper(a.SOURCESYSTEM) = upper(b.sourceSystem)) when matched then update set UPDATE_TIME = #{sourceInfo.updateTime}
,create_Time = #{sourceInfo.createTime}
,SOURCEFIRM = #{sourceInfo.sourceFirm,jdbcType=VARCHAR}
,DATANAME = #{sourceInfo.dataName,jdbcType=VARCHAR}
,DATA_ID = #{sourceInfo.dataId,jdbcType=VARCHAR}
,PROJECT_NAME = #{sourceInfo.projectName,jdbcType=VARCHAR}
,CENTER_NAME = #{sourceInfo.centerName,jdbcType=VARCHAR}
,CENTER_ID = #{sourceInfo.centerId,jdbcType=VARCHAR}
when not matched then insert values (#{sourceInfo.id},#{sourceInfo.createTime},#{sourceInfo.updateTime}, #{sourceInfo.sourceProtocol,jdbcType=VARCHAR},#{sourceInfo.tableName,jdbcType=VARCHAR}, #{sourceInfo.sourceSystem,jdbcType=VARCHAR},#{sourceInfo.sourceFirm,jdbcType=VARCHAR},#{sourceInfo.dataName,jdbcType=VARCHAR}, #{sourceInfo.dataId,jdbcType=VARCHAR},#{sourceInfo.projectName,jdbcType=VARCHAR},#{sourceInfo.centerName,jdbcType=VARCHAR}, #{sourceInfo.centerId,jdbcType=VARCHAR})

mapper.select:
select ID,CREATE_TIME,UPDATE_TIME,SOURCEPROTOCOL,TABLENAME,SOURCESYSTEM,SOURCEFIRM,DATANAME,DATA_ID,PROJECT_NAME,
CENTER_NAME,CENTER_ID from SourceInfo where SOURCEPROTOCOL=#{sourceProtocol} and TABLENAME=#{tableName}
and SOURCESYSTEM=#{sourceSystem}

select distinct PRIMARYORGANIZATIONCH||SECONDARYORGANIZATIONCH , '1' as mainClassifyId , '数据组织分类' as mainClassifyCh , SJYJFL as primaryClassifyId , PRIMARYORGANIZATIONCH as primaryClassifyCh , SJEJFL as secondaryClassifyId , SECONDARYORGANIZATIONCH as secondaryClassifyCh from CLASSIFY_INTERFACE_ALL_DATE where SJXJBM is not null
and PRIMARYORGANIZATIONCH = #{primaryClassifyCh}
order by sjyjfl

select value from object_manage_standard where deleted='0' and rownum = 1


        and remarks = #{classType}


        and  text = #{subClassType}

select.if:
select v3.codename as codeName from v_classify_info v1 left join v_classify_info v2 on v1.codeid=v2.parcodeid left join v_classify_info v3 on v3.parcodeid = v2.codeid
v1.codetext = '数据来源分类' and rownum =1
and v3.codetext = #{midClassType}

select v2.codename as codeName from v_classify_info v1 left join v_classify_info v2 on v1.codeid=v2.parcodeid
v1.codetext = '数据来源分类' and rownum =1
and v2.codetext = #{midClassType}

mapper.select:
select value from object_manage_standard where deleted='0' and rownum = 1

    and text = #{mainClassName}


    and text = #{mainClassName}


    and text = #{mainClassName}||'库'

select distinct v2.codeid ||'/'|| v3.codeid from v_classify_info v1 left join v_classify_info v2 on v1.codeid=v2.parcodeid left join v_classify_info v3 on v2.codeid=v3.parcodeid where
v1.codetext = '数据组织分类'
v1.codetext = '数据来源分类'
and v2.codetext = #{firstClassCh}
and v3.codetext = #{secondClassCh}
and v3.codetext is null

select ids from(

    select distinct parentId as ids from(select v1.codeid as parentId ,v1.codetext as parentText ,v2.codeid as childId
    ,v2.codetext as childText
    from v_classify_info v1
    left join v_classify_info v2 on v1.codeid = v2.parcodeid)
    where parentText =#{parentText}

        and childText is null


        and childText =#{childText}




    select  distinct childId  as ids from(select v1.codeid as parentId ,v1.codetext as parentText ,v2.codeid as childId
    ,v2.codetext as childText
    from v_classify_info v1
    left join v_classify_info v2 on v1.codeid = v2.parcodeid)
    where parentText =#{parentText}

        and childText is null


        and childText =#{childText}


)

