update USER_AUTHORITY set CMN_MEMO = #{cmnMemo} , MODULECODE =#{moduleCode} ,
MODULENAME = #{moduleName}, ISCREATER = #{isCreater} ,USERNAME = #{userName},
CMN_NAME =#{cmnName}, CREATE_TIME = sysdate, USERID = #{userId} where ORGANID = #{organId} and ID =#{id}
